def f1(s, a):
    robot_x = s[0]
    target_cx = s[9] + s[17] / 2.0
    to_target_x = target_cx - robot_x
    return (a[0] > 0) if (to_target_x > 0) else (a[0] < 0)

def f2(s, a):
    robot_y = s[1]
    target_cy = s[10] + s[18] / 2.0
    to_target_y = target_cy - robot_y
    return (a[1] > 0) if (to_target_y > 0) else (a[1] < 0)

def f4(s, a):
    robot_x = s[0]
    robot_base_radius = s[3]
    wall_x = s[19]
    to_wall_x = wall_x - (robot_x + robot_base_radius)
    return (a[0] > 0) if (to_wall_x > 0) else (a[0] < 0)

def f7(s, a):
    robot_x = s[0]
    robot_base_radius = s[3]
    wall_x = s[19]
    left_of_wall = (robot_x + robot_base_radius) < wall_x
    return left_of_wall and (a[0] > 0)

def f10(s, a):
    robot_x = s[0]
    robot_base_radius = s[3]
    wall_right = s[19] + s[27] + robot_base_radius
    passed = (robot_x + robot_base_radius) >= wall_right
    return passed and (a[0] > 0)

def f16(s, a):
    robot_x = s[0]
    target_cx = s[9] + s[17] / 2.0
    left_of_target = robot_x < target_cx
    return left_of_target and (a[0] > 0)

def f17(s, a):
    robot_y = s[1]
    target_cy = s[10] + s[18] / 2.0
    below_target = robot_y < target_cy
    return below_target and (a[1] > 0)

def f18(s, a):
    robot_y = s[1]
    target_cy = s[10] + s[18] / 2.0
    above_target = robot_y > target_cy
    return above_target and (a[1] < 0)

def f19(s, a):
    robot_x = s[0]
    target_cx = s[9] + s[17] / 2.0
    right_of_target = robot_x > target_cx
    return right_of_target and (a[0] < 0)

def f29(s, a):
    robot_x = s[0]
    robot_base_radius = s[3]
    wall_x = s[19]
    dist = wall_x - (robot_x + robot_base_radius)
    return (dist > 0) and (dist < 0.15) and (a[0] > 0)

def f37(s, a):
    robot_y = s[1]
    target_cy = s[10] + s[18] / 2.0
    return (robot_y > target_cy) and (a[1] < 0)

def f45(s, a):
    robot_x = s[0]
    robot_base_radius = s[3]
    wall_right = s[19] + s[27] + robot_base_radius
    past = (robot_x + robot_base_radius) >= wall_right
    return past and (a[0] > 0)

def f74(s, a):
    robot_y = s[1]
    gap_upper = s[20] + s[28] + (s[30] - (s[20] + s[28]))
    robot_above_gap = robot_y > gap_upper
    return robot_above_gap and (a[0] < 0) and (a[1] < 0)
